const raw = $json.body?.company || '';
const company = raw.trim();
if (!company || company.length < 2 || company.length > 120) {
  return [{json: { valid: false, error: "Please enter a valid company name." }}];
}
return [{json: { valid: true, company }}];

const results = $json;
const arr = Array.isArray(results) ? results : [];
if (arr.length === 0) {
  return [{json: {found: false, isPublic: false, companyName: $('Validate Input').first().json.company}}];
}
const best = arr[0];
return [{json: {
  found: true, isPublic: true,
  ticker: best.symbol,
  companyName: best.name || best.symbol,
  exchange: best.exchangeShortName || 'N/A',
  originalQuery: $('Validate Input').first().json.company
}}];

// Assemble Payload: merge all financial data into a single structured object
const items = $input.all();

// Helper to safely get first array element
const getFirst = (arr) => Array.isArray(arr) && arr.length > 0 ? arr[0] : {};

// Extract data from each source
const profile = getFirst(items[0]?.json);
const metrics = getFirst(items[1]?.json);
const ratios = getFirst(items[2]?.json);
const quote = getFirst(items[3]?.json);
const newsArray = items[4]?.json || [];

// Get ticker info from upstream
const tickerInfo = $('Resolve Ticker').first().json;

// Format numbers for display
const fmt = (val, decimals = 2) => {
  if (val === null || val === undefined || isNaN(val)) return 'N/A';
  return Number(val).toFixed(decimals);
};

const fmtBillion = (val) => {
  if (val === null || val === undefined || isNaN(val)) return 'N/A';
  return (val / 1e9).toFixed(2) + 'B';
};

const fmtPercent = (val) => {
  if (val === null || val === undefined || isNaN(val)) return 'N/A';
  return (val * 100).toFixed(2) + '%';
};

// Analyze news sentiment
const analyzeSentiment = (newsItems) => {
  if (!Array.isArray(newsItems) || newsItems.length === 0) {
    return { score: 0, label: 'Neutral', summary: 'No recent news available.' };
  }

  // Simple sentiment based on title keywords
  let positiveCount = 0;
  let negativeCount = 0;

  const positiveWords = ['surge', 'gain', 'profit', 'growth', 'beat', 'success', 'rise', 'up', 'high', 'strong'];
  const negativeWords = ['fall', 'loss', 'decline', 'miss', 'weak', 'down', 'low', 'concern', 'risk', 'drop'];

  newsItems.forEach(item => {
    const text = (item.title + ' ' + (item.text || '')).toLowerCase();
    positiveWords.forEach(word => { if (text.includes(word)) positiveCount++; });
    negativeWords.forEach(word => { if (text.includes(word)) negativeCount++; });
  });

  const total = positiveCount + negativeCount;
  const score = total === 0 ? 0 : (positiveCount - negativeCount) / total;

  let label = 'Neutral';
  if (score > 0.2) label = 'Positive';
  else if (score < -0.2) label = 'Negative';

  return {
    score: fmt(score, 2),
    label,
    summary: `${newsItems.length} recent articles analyzed. Sentiment: ${label}.`
  };
};

const sentiment = analyzeSentiment(newsArray);

// Build comprehensive payload
const payload = {
  ticker: tickerInfo.ticker || 'N/A',
  companyName: tickerInfo.companyName || profile.companyName || 'N/A',
  exchange: tickerInfo.exchange || profile.exchangeShortName || 'N/A',

  profile: {
    sector: profile.sector || 'N/A',
    industry: profile.industry || 'N/A',
    description: profile.description || 'No description available.',
    ceo: profile.ceo || 'N/A',
    website: profile.website || 'N/A',
    employees: profile.fullTimeEmployees || 'N/A',
    country: profile.country || 'N/A',
    ipoDate: profile.ipoDate || 'N/A'
  },

  quote: {
    price: fmt(quote.price),
    change: fmt(quote.change),
    changePercent: fmtPercent(quote.changesPercentage / 100),
    dayLow: fmt(quote.dayLow),
    dayHigh: fmt(quote.dayHigh),
    yearLow: fmt(quote.yearLow),
    yearHigh: fmt(quote.yearHigh),
    marketCap: fmtBillion(quote.marketCap),
    volume: quote.volume || 'N/A',
    avgVolume: quote.avgVolume || 'N/A',
    previousClose: fmt(quote.previousClose)
  },

  metrics: {
    peRatio: fmt(metrics.peRatioTTM),
    priceToBook: fmt(metrics.pbRatioTTM),
    priceToSales: fmt(metrics.priceToSalesRatioTTM),
    evToEbitda: fmt(metrics.enterpriseValueOverEBITDATTM),
    roe: fmtPercent(metrics.roeTTM),
    roa: fmtPercent(metrics.roaTTM),
    debtToEquity: fmt(metrics.debtToEquityTTM),
    currentRatio: fmt(metrics.currentRatioTTM),
    dividendYield: fmtPercent(metrics.dividendYieldTTM)
  },

  ratios: {
    grossProfitMargin: fmtPercent(ratios.grossProfitMarginTTM),
    operatingProfitMargin: fmtPercent(ratios.operatingProfitMarginTTM),
    netProfitMargin: fmtPercent(ratios.netProfitMarginTTM),
    returnOnEquity: fmtPercent(ratios.returnOnEquityTTM),
    returnOnAssets: fmtPercent(ratios.returnOnAssetsTTM),
    assetTurnover: fmt(ratios.assetTurnoverTTM),
    inventoryTurnover: fmt(ratios.inventoryTurnoverTTM)
  },

  news: newsArray.slice(0, 10).map(item => ({
    title: item.title || 'No title',
    publishedDate: item.publishedDate || 'N/A',
    site: item.site || 'N/A',
    url: item.url || '#'
  })),

  sentiment: sentiment,

  generatedAt: new Date().toISOString()
};

return [{ json: payload }];

const claude = $input.first().json;
const memo = claude.content[0].text;
const meta = $('Resolve Ticker').first().json;
return [{json:{
  success:true,
  memo:{
    type:'private',
    content:memo,
    company:meta.companyName,
    ticker:null,
    sector:'Private/Startup',
    industry:'N/A',
    price:null,
    market_cap:null,
    market_cap_formatted:null,
    image:null,
    sentiment:null,
    recommendation_system:'vc_tier'
  },
  metadata:{
    generated_at:new Date().toISOString(),
    model:'claude-sonnet-4-6',
    data_sources:['AI Knowledge Base','Public Information'],
    note:'Limited data available for private companies. Analysis based on publicly known information.',
    disclaimer:'Generated by MemoAI. Not financial advice.'
  }
}}];

const claude = $input.first().json;
const memo = claude.content[0].text;
const payload = $('Assemble Payload').first().json;

// Extract recommendation from memo text
const extractRecommendation = (text) => {
  const match = text.match(/RECOMMENDATION:\s*(CONVICTION BUY|ACCUMULATE|HOLD|MONITOR|REDUCE)/i);
  return match ? match[1].toUpperCase() : 'HOLD';
};

const recommendation = extractRecommendation(memo);

return [{json:{
  success: true,
  memo: {
    type: 'public',
    content: memo,
    company: payload.companyName,
    ticker: payload.ticker,
    sector: payload.profile.sector,
    industry: payload.profile.industry,
    price: payload.quote.price,
    market_cap: payload.quote.marketCap,
    market_cap_formatted: payload.quote.marketCap,
    image: null,
    sentiment: payload.sentiment.label,
    recommendation: recommendation,
    recommendation_system: 'equity_tier'
  },
  metadata: {
    generated_at: payload.generatedAt,
    model: 'claude-sonnet-4-6',
    data_sources: ['Financial Modeling Prep API', 'Market Data', 'News Sentiment'],
    disclaimer: 'Generated by MemoAI. Not financial advice.'
  }
}}];

const errorMsg = $input.first().json?.message || 'An unexpected error occurred.';
return [{json:{
  success:false,
  error:errorMsg,
  retry:true,
  metadata:{generated_at:new Date().toISOString()}
}}];
